#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

/* == EXEMPLE =======================================
 * 2 enfants ecrivent dans un pipe, parent lit tout
 * ================================================= */
void example_multi_pipe(void) {
    int fd[2];
    pipe(fd);
    for (int i = 0; i < 2; i++) {
        if (fork() == 0) {
            close(fd[0]);
            char m[32];
            snprintf(m, sizeof(m), "child %d\n", i);
            write(fd[1], m, strlen(m));
            close(fd[1]);
            _exit(0);
        }
    }
    close(fd[1]);
    wait(NULL); wait(NULL);
    char buf[128];
    ssize_t n = read(fd[0], buf, sizeof(buf)-1);
    buf[n] = '\0';
    printf("%s", buf);
    close(fd[0]);
}
/* Resultat: child 0\nchild 1\n */

